contracts/AccessControl.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

interface IGenomeRegistry {
    function getGenomeMetadata(bytes32 _datasetId) external view returns (
        bytes32, string memory, address, uint256, uint256, bool, string memory, string memory, uint256
    );
    function incrementAccessCount(bytes32 _datasetId) external;
    function addAuditLog(string calldata, address, bytes32, string calldata) external;
}

contract AccessControl is ReentrancyGuard {

    enum RequestStatus { Pending, Approved, Rejected, Revoked }

    struct AccessRequest {
        bytes32    requestId;
        bytes32    datasetId;
        address    researcher;
        string     researchObjective;
        string     fundingSource;
        uint256    durationDays;
        uint256    timestamp;
        uint256    approvedAt;
        RequestStatus status;
        string     signatureHash;
        string     encryptedKeyHash; // stored after approval
    }

    IGenomeRegistry public genomeRegistry;

    mapping(bytes32 => AccessRequest)   public requests;
    mapping(address => bytes32[])        public researcherRequests;
    mapping(bytes32 => bytes32[])        public datasetRequests;  // datasetId => requestIds
    mapping(bytes32 => mapping(address => bool)) public activeAccess; // datasetId => researcher => bool

    event AccessRequested(bytes32 indexed requestId, bytes32 indexed datasetId, address researcher);
    event AccessApproved(bytes32 indexed requestId, bytes32 indexed datasetId, address researcher);
    event AccessRejected(bytes32 indexed requestId);
    event AccessRevoked(bytes32 indexed requestId);

    constructor(address _genomeRegistry) {
        genomeRegistry = IGenomeRegistry(_genomeRegistry);
    }

    function requestAccess(
        bytes32 _datasetId,
        string calldata _researchObjective,
        string calldata _fundingSource,
        uint256 _durationDays,
        string calldata _signatureHash
    ) external nonReentrant returns (bytes32) {
        bytes32 requestId = keccak256(
            abi.encodePacked(_datasetId, msg.sender, block.timestamp, _signatureHash)
        );
        require(requests[requestId].researcher == address(0), "Request exists");

        requests[requestId] = AccessRequest({
            requestId:          requestId,
            datasetId:          _datasetId,
            researcher:         msg.sender,
            researchObjective:  _researchObjective,
            fundingSource:      _fundingSource,
            durationDays:       _durationDays,
            timestamp:          block.timestamp,
            approvedAt:         0,
            status:             RequestStatus.Pending,
            signatureHash:      _signatureHash,
            encryptedKeyHash:   ""
        });

        researcherRequests[msg.sender].push(requestId);
        datasetRequests[_datasetId].push(requestId);

        genomeRegistry.addAuditLog("requestAccess", msg.sender, _datasetId, _signatureHash);
        emit AccessRequested(requestId, _datasetId, msg.sender);
        return requestId;
    }

    function approveAccess(
        bytes32 _requestId,
        string calldata _encryptedKeyHash,
        string calldata _ownerSignatureHash
    ) external nonReentrant {
        AccessRequest storage req = requests[_requestId];
        require(req.researcher != address(0), "Request not found");
        require(req.status == RequestStatus.Pending, "Not pending");

        req.status           = RequestStatus.Approved;
        req.approvedAt       = block.timestamp;
        req.encryptedKeyHash = _encryptedKeyHash;

        activeAccess[req.datasetId][req.researcher] = true;
        genomeRegistry.incrementAccessCount(req.datasetId);
        genomeRegistry.addAuditLog("approveAccess", msg.sender, req.datasetId, _ownerSignatureHash);

        emit AccessApproved(_requestId, req.datasetId, req.researcher);
    }

    function rejectAccess(bytes32 _requestId) external {
        AccessRequest storage req = requests[_requestId];
        require(req.status == RequestStatus.Pending, "Not pending");
        req.status = RequestStatus.Rejected;
        genomeRegistry.addAuditLog("rejectAccess", msg.sender, req.datasetId, "");
        emit AccessRejected(_requestId);
    }

    function revokeAccess(bytes32 _requestId) external nonReentrant {
        AccessRequest storage req = requests[_requestId];
        require(req.status == RequestStatus.Approved, "Not approved");
        req.status = RequestStatus.Revoked;
        activeAccess[req.datasetId][req.researcher] = false;
        genomeRegistry.addAuditLog("revokeAccess", msg.sender, req.datasetId, "");
        emit AccessRevoked(_requestId);
    }

    function hasActiveAccess(bytes32 _datasetId, address _researcher) external view returns (bool) {
        return activeAccess[_datasetId][_researcher];
    }

    function getRequest(bytes32 _requestId) external view returns (AccessRequest memory) {
        return requests[_requestId];
    }

    function getResearcherRequests(address _researcher) external view returns (bytes32[] memory) {
        return researcherRequests[_researcher];
    }

    function getDatasetRequests(bytes32 _datasetId) external view returns (bytes32[] memory) {
        return datasetRequests[_datasetId];
    }
}

contracts/GenomeRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

contract GenomeRegistry is Ownable, ReentrancyGuard, Pausable {

    struct GenomeDataset {
        bytes32  datasetHash;
        string   ipfsCID;
        address  owner;
        uint256  timestamp;
        uint256  price;         // in wei
        bool     isActive;
        string   signatureHash;
        string   metadata;      // JSON: ancestry, sequencingType, etc.
        uint256  accessCount;
    }

    struct AuditLog {
        string   actionType;    // uploadGenome | requestAccess | approveAccess | downloadData
        address  actor;
        bytes32  datasetId;
        string   signatureHash;
        uint256  timestamp;
    }

    // datasetId => GenomeDataset
    mapping(bytes32 => GenomeDataset) public datasets;
    // owner => list of datasetIds
    mapping(address => bytes32[]) public ownerDatasets;
    // audit logs
    AuditLog[] public auditLogs;
    bytes32[] public allDatasetIds;

    event GenomeRegistered(bytes32 indexed datasetId, address indexed owner, string ipfsCID, uint256 price);
    event DatasetPriceUpdated(bytes32 indexed datasetId, uint256 newPrice);
    event DatasetDeactivated(bytes32 indexed datasetId);
    event AuditLogCreated(string actionType, address actor, bytes32 datasetId, uint256 timestamp);

    modifier onlyDatasetOwner(bytes32 _datasetId) {
        require(datasets[_datasetId].owner == msg.sender, "Not dataset owner");
        _;
    }

    modifier datasetExists(bytes32 _datasetId) {
        require(datasets[_datasetId].owner != address(0), "Dataset does not exist");
        _;
    }

    function registerGenome(
        bytes32  _datasetHash,
        string   calldata _ipfsCID,
        uint256  _price,
        string   calldata _signatureHash,
        string   calldata _metadata
    ) external nonReentrant whenNotPaused returns (bytes32) {
        bytes32 datasetId = keccak256(
            abi.encodePacked(_datasetHash, msg.sender, block.timestamp)
        );
        require(datasets[datasetId].owner == address(0), "Dataset already registered");

        datasets[datasetId] = GenomeDataset({
            datasetHash:    _datasetHash,
            ipfsCID:        _ipfsCID,
            owner:          msg.sender,
            timestamp:      block.timestamp,
            price:          _price,
            isActive:       true,
            signatureHash:  _signatureHash,
            metadata:       _metadata,
            accessCount:    0
        });

        ownerDatasets[msg.sender].push(datasetId);
        allDatasetIds.push(datasetId);

        _addAuditLog("uploadGenome", msg.sender, datasetId, _signatureHash);
        emit GenomeRegistered(datasetId, msg.sender, _ipfsCID, _price);
        return datasetId;
    }

    function getGenomeMetadata(bytes32 _datasetId)
        external view datasetExists(_datasetId)
        returns (GenomeDataset memory)
    {
        return datasets[_datasetId];
    }

    function getOwnerDatasets(address _owner) external view returns (bytes32[] memory) {
        return ownerDatasets[_owner];
    }

    function getAllDatasets() external view returns (bytes32[] memory) {
        return allDatasetIds;
    }

    function updatePrice(bytes32 _datasetId, uint256 _newPrice)
        external onlyDatasetOwner(_datasetId)
    {
        datasets[_datasetId].price = _newPrice;
        emit DatasetPriceUpdated(_datasetId, _newPrice);
    }

    function deactivateDataset(bytes32 _datasetId)
        external onlyDatasetOwner(_datasetId)
    {
        datasets[_datasetId].isActive = false;
        emit DatasetDeactivated(_datasetId);
    }

    function incrementAccessCount(bytes32 _datasetId) external {
        datasets[_datasetId].accessCount++;
    }

    function _addAuditLog(
        string memory _actionType,
        address _actor,
        bytes32 _datasetId,
        string memory _signatureHash
    ) internal {
        auditLogs.push(AuditLog({
            actionType:    _actionType,
            actor:         _actor,
            datasetId:     _datasetId,
            signatureHash: _signatureHash,
            timestamp:     block.timestamp
        }));
        emit AuditLogCreated(_actionType, _actor, _datasetId, block.timestamp);
    }

    function addAuditLog(
        string calldata _actionType,
        address _actor,
        bytes32 _datasetId,
        string calldata _signatureHash
    ) external {
        _addAuditLog(_actionType, _actor, _datasetId, _signatureHash);
    }

    function getAuditLogs() external view returns (AuditLog[] memory) {
        return auditLogs;
    }

    function pause()   external onlyOwner { _pause(); }
    function unpause() external onlyOwner { _unpause(); }
}

contracts/PaymentContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

interface IAccessControl {
    function getRequest(bytes32 _requestId) external view returns (
        bytes32, bytes32, address, string memory, string memory,
        uint256, uint256, uint256, uint8, string memory, string memory
    );
    function approveAccess(bytes32, string calldata, string calldata) external;
}

interface IGenomeRegistry2 {
    function getGenomeMetadata(bytes32 _datasetId) external view returns (
        bytes32, string memory, address, uint256, uint256, bool, string memory, string memory, uint256
    );
}

contract PaymentContract is Ownable, ReentrancyGuard {

    uint256 public platformFeeBps = 500; // 5% platform commission (basis points)

    struct Payment {
        bytes32  requestId;
        bytes32  datasetId;
        address  researcher;
        address  dataOwner;
        uint256  amount;
        uint256  platformFee;
        uint256  ownerPayout;
        uint256  timestamp;
        bool     processed;
    }

    mapping(bytes32 => Payment)  public payments;
    mapping(address => uint256)  public ownerEarnings;
    mapping(address => uint256)  public ownerTotalAccesses;
    uint256 public totalPlatformRevenue;

    IAccessControl  public accessControl;
    IGenomeRegistry2 public genomeRegistry;

    event PaymentProcessed(bytes32 indexed requestId, address researcher, address owner, uint256 amount);
    event OwnerWithdrawal(address indexed owner, uint256 amount);
    event PlatformFeeUpdated(uint256 newFeeBps);

    constructor(address _accessControl, address _genomeRegistry) {
        accessControl  = IAccessControl(_accessControl);
        genomeRegistry = IGenomeRegistry2(_genomeRegistry);
    }

    function processPayment(
        bytes32 _requestId,
        bytes32 _datasetId,
        address _dataOwner,
        string calldata _encryptedKeyHash,
        string calldata _ownerSig
    ) external payable nonReentrant {
        require(msg.value > 0, "Payment required");
        require(!payments[_requestId].processed, "Already paid");

        uint256 fee    = (msg.value * platformFeeBps) / 10000;
        uint256 payout = msg.value - fee;

        payments[_requestId] = Payment({
            requestId:   _requestId,
            datasetId:   _datasetId,
            researcher:  msg.sender,
            dataOwner:   _dataOwner,
            amount:      msg.value,
            platformFee: fee,
            ownerPayout: payout,
            timestamp:   block.timestamp,
            processed:   true
        });

        ownerEarnings[_dataOwner]      += payout;
        ownerTotalAccesses[_dataOwner] += 1;
        totalPlatformRevenue           += fee;

        accessControl.approveAccess(_requestId, _encryptedKeyHash, _ownerSig);
        emit PaymentProcessed(_requestId, msg.sender, _dataOwner, msg.value);
    }

    function withdraw() external nonReentrant {
        uint256 amount = ownerEarnings[msg.sender];
        require(amount > 0, "Nothing to withdraw");
        ownerEarnings[msg.sender] = 0;
        (bool ok,) = payable(msg.sender).call{value: amount}("");
        require(ok, "Transfer failed");
        emit OwnerWithdrawal(msg.sender, amount);
    }

    function withdrawPlatformFees() external onlyOwner {
        uint256 amount = totalPlatformRevenue;
        totalPlatformRevenue = 0;
        (bool ok,) = payable(owner()).call{value: amount}("");
        require(ok, "Transfer failed");
    }

    function getOwnerEarnings(address _owner) external view returns (uint256) {
        return ownerEarnings[_owner];
    }

    function setPlatformFee(uint256 _feeBps) external onlyOwner {
        require(_feeBps <= 2000, "Max 20%");
        platformFeeBps = _feeBps;
        emit PlatformFeeUpdated(_feeBps);
    }

    receive() external payable {}
}

